    81→a:hover { color: var(--polizei-pale); }
    82→a:focus-visible { outline: 2px solid var(--polizei-light); outline-offset: 2px; }
    83→
    84→.container { max-width: var(--container); margin: 0 auto; padding: 0 24px; }
    85→
    86→/* ===== Scroll Reveal ===== */
