/* ===== Form ===== */
.krisen-form {
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  padding: 32px;
}

.krisen-form__section {
  margin-bottom: 32px;
}

.krisen-form__section-title {
  font-size: .72rem;
  font-family: var(--font-mono);
  letter-spacing: 3px;
  text-transform: uppercase;
  color: var(--bos-gold);
  margin-bottom: 16px;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--gray-100);
}

.krisen-form__row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  margin-bottom: 16px;
}

input.old_string:
.krisen-form__group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

input.new_string:
.krisen-form__group {
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 0;
}

