/* ===== Krisenkommunikation Page ===== */

.krisen-page {
  max-width: 860px;
  margin: 0 auto;
  padding: calc(var(--nav-h) + 48px) 24px 80px;
}

.krisen-page h1 {
  font-size: 1.6rem;
  font-weight: 800;
  color: var(--gray-900);
  margin-bottom: 8px;
}

.krisen-page .subtitle {
  font-size: .85rem;
  color: var(--gray-500);
  margin-bottom: 40px;
}

/* ===== Download Card ===== */
.download-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 28px 32px;
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  transition: border-color .2s, box-shadow .2s;
}

.download-card:hover {
  border-color: var(--polizei-mid);
  box-shadow: 0 2px 12px rgba(59,90,140,.08);
}

.download-card__info h2 {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--gray-900);
  margin-bottom: 4px;
}

.download-card__info p {
  font-size: .85rem;
  color: var(--gray-500);
}

.download-card .btn i {
  width: 18px;
  height: 18px;
}

/* ===== Divider ===== */
.form-divider {
  display: flex;
  align-items: center;
  gap: 16px;
  margin: 40px 0;
  color: var(--gray-300);
  font-size: .82rem;
  font-weight: 600;
  letter-spacing: .5px;
  text-transform: uppercase;
}

.form-divider::before,
.form-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--gray-200);
}

/* ===== Form ===== */
.krisen-form {
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  padding: 32px;
}

.krisen-form__section {
  margin-bottom: 32px;
}

.krisen-form__section-title {
  font-size: .72rem;
  font-family: var(--font-mono);
  letter-spacing: 3px;
  text-transform: uppercase;
  color: var(--bos-gold);
  margin-bottom: 16px;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--gray-100);
}

.krisen-form__row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  margin-bottom: 16px;
}

.krisen-form__row--2 {
  grid-template-columns: repeat(2, 1fr);
}

.krisen-form__row--3 {
  grid-template-columns: repeat(3, 1fr);
}

.krisen-form__group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.krisen-form__group--full {
  grid-column: 1 / -1;
}

.krisen-form__group label {
  font-size: .78rem;
  font-weight: 600;
  color: var(--gray-700);
  letter-spacing: .2px;
}

.krisen-form__group input,
.krisen-form__group textarea {
  font-family: var(--font-main);
  font-size: .88rem;
  padding: 10px 12px;
  border: 1px solid var(--gray-200);
  border-radius: var(--radius);
  background: var(--off-white);
  color: var(--gray-900);
  transition: border-color .2s, box-shadow .2s;
}

.krisen-form__group input:focus,
.krisen-form__group textarea:focus {
  outline: none;
  border-color: var(--polizei-mid);
  box-shadow: 0 0 0 3px rgba(58,90,140,.1);
}

.krisen-form__group textarea {
  resize: vertical;
  min-height: 72px;
}

/* ===== Weitergabe Table ===== */
.weitergabe-table {
  width: 100%;
  border-collapse: collapse;
  font-size: .85rem;
}

.weitergabe-table th {
  font-size: .72rem;
  font-weight: 700;
  color: var(--gray-500);
  text-transform: uppercase;
  letter-spacing: .5px;
  text-align: left;
  padding: 8px 12px;
  border-bottom: 2px solid var(--gray-200);
}

.weitergabe-table td {
  padding: 10px 12px;
  border-bottom: 1px solid var(--gray-100);
  vertical-align: middle;
}

.weitergabe-table .org-name {
  font-weight: 600;
  color: var(--gray-900);
  white-space: nowrap;
}

.weitergabe-table .org-name--custom input {
  font-family: var(--font-main);
  font-size: .85rem;
  padding: 6px 10px;
  border: 1px solid var(--gray-200);
  border-radius: var(--radius);
  background: var(--off-white);
  color: var(--gray-900);
  width: 100%;
  transition: border-color .2s;
}

.weitergabe-table .org-name--custom input:focus {
  outline: none;
  border-color: var(--polizei-mid);
}

.weitergabe-table input[type="checkbox"] {
  width: 18px;
  height: 18px;
  cursor: pointer;
  accent-color: var(--polizei-mid);
}

.weitergabe-table input[type="text"] {
  font-family: var(--font-main);
  font-size: .85rem;
  padding: 6px 10px;
  border: 1px solid var(--gray-200);
  border-radius: var(--radius);
  background: var(--off-white);
  color: var(--gray-900);
  width: 100%;
  transition: border-color .2s;
}

.weitergabe-table input[type="text"]:focus {
  outline: none;
  border-color: var(--polizei-mid);
}

/* ===== Form Actions ===== */
.krisen-form__actions {
  display: flex;
  gap: 12px;
  margin-top: 32px;
  padding-top: 24px;
  border-top: 1px solid var(--gray-100);
}

.btn--outline-gray {
  background: transparent;
  color: var(--gray-500);
  border-color: var(--gray-200);
}

.btn--outline-gray:hover {
  border-color: var(--gray-500);
  color: var(--gray-700);
  transform: translateY(-1px);
}

/* ===== Responsive ===== */
@media (max-width: 768px) {
  .krisen-page {
    padding: calc(var(--nav-h) + 32px) 16px 60px;
  }

  .download-card {
    flex-direction: column;
    align-items: flex-start;
    padding: 20px;
  }

  .krisen-form {
    padding: 20px 16px;
  }

  .krisen-form__row,
  .krisen-form__row--2,
  .krisen-form__row--3 {
    grid-template-columns: 1fr;
  }

  .weitergabe-table {
    display: block;
    overflow-x: auto;
  }

  .krisen-form__actions {
    flex-direction: column;
  }

  .krisen-form__actions .btn {
    width: 100%;
    justify-content: center;
  }
}

@media (max-width: 480px) {
  .form-divider {
    margin: 28px 0;
  }
}

