  font-size: .85rem;
  color: var(--gray-500);
  margin-bottom: 40px;
}

/* ===== Download Card ===== */
.download-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 28px 32px;
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  transition: border-color .2s, box-shadow .2s;
}

.download-card:hover {
  border-color: var(--polizei-mid);
  box-shadow: 0 2px 12px rgba(59,90,140,.08);
}

.download-card__info h2 {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--gray-900);
  margin-bottom: 4px;
}

.download-card__info p {
  font-size: .85rem;
  color: var(--gray-500);
}

.download-card .btn i {
  width: 18px;
  height: 18px;
}

/* ===== Divider ===== */
.form-divider {
  display: flex;
  align-items: center;
  gap: 16px;
  margin: 40px 0;
  color: var(--gray-300);
