.krisen-intro {
  font-size: .92rem;
  color: var(--gray-700);
  line-height: 1.7;
  margin-bottom: 40px;
}

.krisen-section-title {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--polizei-navy);
  margin-bottom: 16px;
  margin-top: 40px;
}

.krisen-section-title:first-of-type {
  margin-top: 0;
}

.krisen-section-title i {
  width: 20px;
