  color: var(--bos-gold);
}

.krisen-form-intro {
  font-size: .85rem;
  color: var(--gray-500);
  margin-bottom: 16px;
}

/* ===== Download Card ===== */
.download-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 24px;
  padding: 28px 32px;
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  transition: border-color .2s, box-shadow .2s;
}

.download-card:hover {
  border-color: var(--polizei-mid);
  box-shadow: 0 2px 12px rgba(59,90,140,.08);
}

.download-card__info h2 {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--gray-900);
  margin-bottom: 4px;
}

.download-card__info p {
  font-size: .85rem;
  color: var(--gray-500);
}

.download-card .btn i {
  width: 18px;
  height: 18px;
}

/* ===== Divider ===== */
.form-divider {
  display: flex;
  align-items: center;
  gap: 16px;
  margin: 40px 0;
  color: var(--gray-300);
  font-size: .82rem;
  font-weight: 600;
  letter-spacing: .5px;
  text-transform: uppercase;
}

.form-divider::before,
.form-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--gray-200);
}

/* ===== Form ===== */
.krisen-form {
  background: var(--white);
  border: 1px solid var(--gray-100);
  border-radius: var(--radius);
  padding: 32px;
  overflow: hidden;
}

.krisen-form__section {
  margin-bottom: 32px;
}

.krisen-form__section-title {
  font-size: .72rem;
  font-family: var(--font-mono);
  letter-spacing: 3px;
  text-transform: uppercase;
  color: var(--bos-gold);
  margin-bottom: 16px;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--gray-100);
}

.krisen-form__row {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
  margin-bottom: 16px;
}

.krisen-form__row--2 {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 16px;
  margin-bottom: 16px;
}

